pub(crate) fn translate_tr(en: &str) -> &str {
    lookup_tr(en).unwrap_or(en)
}

#[cfg(test)]
pub(crate) fn has_translation_tr(en: &str) -> bool {
    lookup_tr(en).is_some()
}

