pub(crate) fn translate_uk(en: &str) -> &str {
    lookup_uk(en).unwrap_or(en)
}

#[cfg(test)]
pub(crate) fn has_translation_uk(en: &str) -> bool {
    lookup_uk(en).is_some()
}

